"""
This module contains the Game class to manage the Checkers game.
"""

class Piece:
    def __init__(self, color, is_king=False):
        self.color = color
        self.is_king = is_king

    def __repr__(self):
        return f"{'K' if self.is_king else ''}{self.color}"

class Board:
    def __init__(self):
        self.board = [[None] * 8 for _ in range(8)]
        self.setup_board()

    def setup_board(self):
        colors = ['b', 'w']
        for i, color in enumerate(colors):
            for j in range((i + 1) % 2, 8, 2):
                self.board[i][j] = Piece(color)
        for i in range(5, 8):
            for j in range(i % 2, 8, 2):
                self.board[i][j] = Piece('b')

    def print_board(self):
        for row in self.board:
            print(" ".join(str(piece) if piece else "." for piece in row))

class Game:
    def __init__(self):
        self.board = Board()
        self.current_player = 'w'

    def switch_turn(self):
        self.current_player = 'b' if self.current_player == 'w' else 'w'

    def make_move(self, start, end):
        piece = self.board.board[start[0]][start[1]]
        if piece and piece.color == self.current_player:
            self.board.board[end[0]][end[1]] = piece
            self.board.board[start[0]][start[1]] = None
            self.switch_turn()
```

